import type { CareerQuestion } from "./rrt-questions";

export const cardiacSonographerQuestionsBatch7: CareerQuestion[] = [
  { id: "cardecho-470", stem: "What is the primary indication for transesophageal echocardiography (TEE) over transthoracic echocardiography (TTE)?", options: ["Superior image quality for posterior structures such as the left atrial appendage, mitral valve, and interatrial septum", "Better visualization of the LV apex", "Assessment of LV ejection fraction in all patients", "Evaluation of pericardial effusion"], correctIndex: 0, rationale: "TEE places the transducer in the esophagus directly behind the heart, providing superior resolution for posterior structures (LA appendage, mitral valve, interatrial septum, aorta) without lung or chest wall interference.", difficulty: 1, category: "Imaging Techniques", topic: "TEE Indications" },
  { id: "cardecho-471", stem: "TEE is considered essential before which cardiac procedure?", options: ["Cardioversion of atrial fibrillation >48 hours duration to rule out LA appendage thrombus", "Routine stress testing", "Annual echocardiographic surveillance", "Pacemaker interrogation"], correctIndex: 0, rationale: "Before cardioversion of AF >48 hours (or unknown duration) without adequate anticoagulation, TEE is performed to exclude LA appendage thrombus. If thrombus is present, cardioversion is deferred and anticoagulation continued.", difficulty: 2, category: "Imaging Techniques", topic: "TEE Indications" },
  { id: "cardecho-472", stem: "Which structure is best evaluated by TEE but poorly visualized on TTE?", options: ["Left atrial appendage", "Left ventricular apex", "Right ventricular outflow tract", "Descending abdominal aorta"], correctIndex: 0, rationale: "The LA appendage is located posteriorly and is the most common site of thrombus in atrial fibrillation. It is poorly visualized by TTE due to its posterior location but is well seen on TEE due to the proximity of the esophageal transducer.", difficulty: 1, category: "Imaging Techniques", topic: "TEE Indications" },
  { id: "cardecho-473", stem: "TEE is indicated during which surgical procedure for real-time cardiac monitoring?", options: ["Cardiac surgery for valve repair/replacement to assess surgical results before chest closure", "Appendectomy", "Knee replacement", "Cataract surgery"], correctIndex: 0, rationale: "Intraoperative TEE is standard during cardiac surgery (valve repair/replacement, CABG, congenital repairs) to assess surgical results, ventricular function, air in cardiac chambers, and residual pathology before leaving the operating room.", difficulty: 1, category: "Imaging Techniques", topic: "TEE Indications" },
  { id: "cardecho-474", stem: "Contraindications to TEE include:", options: ["Esophageal stricture, perforation, active variceal bleeding, and recent esophageal surgery", "History of hypertension", "Prior TTE examination", "Mild gastroesophageal reflux"], correctIndex: 0, rationale: "Absolute TEE contraindications: esophageal perforation, stricture, tumor, active variceal bleeding, and recent esophageal/gastric surgery. Relative contraindications include cervical spine instability, severe coagulopathy, and history of radiation to the chest.", difficulty: 2, category: "Imaging Techniques", topic: "TEE Indications" },
  { id: "cardecho-475", stem: "Contrast echocardiography using agitated saline is primarily used to detect:", options: ["Right-to-left intracardiac shunts such as PFO or ASD", "Coronary artery stenosis", "Valvular calcification", "Pericardial thickening"], correctIndex: 0, rationale: "Agitated saline produces microbubbles that opacify the right heart. Appearance of bubbles in the left heart within 3-5 cardiac cycles indicates an intracardiac shunt (PFO/ASD). Appearance after 5 cycles suggests intrapulmonary shunting.", difficulty: 1, category: "Imaging Techniques", topic: "Contrast Echo" },
  { id: "cardecho-476", stem: "Ultrasound contrast agents containing perfluorocarbon or sulfur hexafluoride microbubbles are used to:", options: ["Enhance left ventricular endocardial border definition and assess myocardial perfusion", "Replace agitated saline for shunt detection", "Measure aortic valve gradients", "Assess pericardial thickness"], correctIndex: 0, rationale: "Commercial contrast agents (Definity, Optison, Lumason) contain gas-filled microbubbles that cross the pulmonary capillary bed to opacify the LV. They improve endocardial border detection in technically difficult studies and enable myocardial perfusion imaging.", difficulty: 2, category: "Imaging Techniques", topic: "Contrast Echo" },
  { id: "cardecho-477", stem: "Contrast echocardiography improves the accuracy of LV ejection fraction assessment in patients with:", options: ["Poor acoustic windows where ≥2 contiguous LV segments are not adequately visualized", "Excellent image quality", "Small body habitus", "Athletes with thin chest walls"], correctIndex: 0, rationale: "ASE guidelines recommend contrast when ≥2 contiguous LV segments are inadequately visualized on non-contrast imaging. Contrast enhances endocardial border delineation, improving accuracy of LVEF, volumes, and wall motion assessment.", difficulty: 2, category: "Imaging Techniques", topic: "Contrast Echo" },
  { id: "cardecho-478", stem: "During a contrast-enhanced echo, the mechanical index (MI) should be set to:", options: ["Low MI (0.1-0.3) for real-time perfusion imaging to avoid microbubble destruction", "Maximum MI (1.9) for best contrast effect", "High MI (>1.0) at all times", "MI is not relevant for contrast studies"], correctIndex: 0, rationale: "Low MI preserves microbubbles for continuous real-time imaging. High MI destroys bubbles (flash replenishment technique for perfusion). For LV opacification, low-intermediate MI is used to maintain adequate contrast without excessive destruction.", difficulty: 3, category: "Imaging Techniques", topic: "Contrast Echo" },
  { id: "cardecho-479", stem: "Exercise stress echocardiography is performed to evaluate:", options: ["Inducible wall motion abnormalities suggesting myocardial ischemia in patients with suspected coronary artery disease", "Valvular stenosis at rest only", "Pericardial disease", "Congenital heart defects in neonates"], correctIndex: 0, rationale: "Stress echo detects ischemia by comparing wall motion at rest and peak stress. New or worsening wall motion abnormalities indicate ischemia in the corresponding coronary territory. Sensitivity 80-85%, specificity 85-90%.", difficulty: 1, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-480", stem: "In exercise stress echocardiography, post-exercise images must be acquired within:", options: ["60-90 seconds after peak exercise because wall motion abnormalities resolve rapidly", "5-10 minutes after exercise", "30 minutes after exercise", "The next day"], correctIndex: 0, rationale: "Post-exercise images must be acquired within 60-90 seconds because exercise-induced wall motion abnormalities may normalize quickly as heart rate decreases. Many labs acquire images during peak exercise on a supine bicycle for optimal timing.", difficulty: 2, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-481", stem: "Dobutamine stress echocardiography is used instead of exercise stress when:", options: ["The patient cannot exercise adequately due to physical limitations such as orthopedic or neurological conditions", "The patient prefers pharmacologic testing", "Exercise stress is always superior", "The patient has a normal resting ECG"], correctIndex: 0, rationale: "Dobutamine stress echo is indicated for patients unable to exercise adequately (orthopedic, neurological, peripheral vascular, or deconditioning). Dobutamine is given IV in escalating doses (5-40 mcg/kg/min) with atropine if needed to reach target heart rate.", difficulty: 2, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-482", stem: "During dobutamine stress echo, a biphasic response in an akinetic segment (improvement at low dose, worsening at high dose) indicates:", options: ["Viable but ischemic myocardium that may benefit from revascularization", "Infarcted myocardium without viability", "Normal myocardium", "Artifact"], correctIndex: 0, rationale: "The biphasic response is the most specific marker of viability with ischemia: low-dose dobutamine (5-10 mcg/kg/min) recruits contractile reserve, then high-dose dobutamine induces ischemia worsening function. This pattern predicts recovery after revascularization.", difficulty: 3, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-483", stem: "Termination criteria for dobutamine stress echocardiography include:", options: ["Achievement of target heart rate, new severe wall motion abnormality, significant arrhythmia, hypotension, or intolerable symptoms", "Completing the full dobutamine protocol regardless of symptoms", "Only achieving target heart rate", "Patient request alone without clinical indication"], correctIndex: 0, rationale: "End points include: target HR (85% MPHR), new/worsening WMA in ≥2 segments, significant arrhythmia (sustained VT, AF with rapid response), symptomatic hypotension (SBP drop >40 mmHg), severe hypertension (>240/120), or intolerable symptoms.", difficulty: 3, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-484", stem: "What is the antidote for dobutamine-induced side effects during stress echocardiography?", options: ["Esmolol (short-acting IV beta-blocker)", "Atropine", "Epinephrine", "Adenosine"], correctIndex: 0, rationale: "Esmolol is a short-acting IV beta-blocker (half-life ~9 minutes) used to reverse dobutamine effects including tachycardia, hypertension, and arrhythmias. Its rapid offset makes it ideal for acute pharmacologic reversal in the stress lab.", difficulty: 2, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-485", stem: "3D echocardiography provides which advantage over 2D echo for LV volume assessment?", options: ["Elimination of geometric assumptions by directly measuring the LV volume without relying on mathematical models", "Lower spatial resolution", "Faster acquisition time", "Better temporal resolution"], correctIndex: 0, rationale: "2D methods (Simpson biplane) assume symmetric LV geometry. 3D echo captures the full LV volume without geometric assumptions, providing more accurate volumes and EF, especially in asymmetric ventricles (e.g., post-MI, RV assessment).", difficulty: 2, category: "Imaging Techniques", topic: "3D Echo" },
  { id: "cardecho-486", stem: "3D TEE is particularly valuable for assessment of:", options: ["Mitral valve anatomy for surgical planning of mitral valve repair, providing the surgeon's view", "LV apical thrombus", "Aortic valve gradients", "Pericardial effusion volume"], correctIndex: 0, rationale: "3D TEE provides an en-face surgeon's view of the mitral valve, showing leaflet pathology, prolapse location, cleft, and annular geometry. This detailed anatomic assessment is essential for surgical planning and intraoperative guidance of repair.", difficulty: 3, category: "Imaging Techniques", topic: "3D Echo" },
  { id: "cardecho-487", stem: "A limitation of real-time 3D echocardiography is:", options: ["Lower temporal and spatial resolution compared to 2D imaging, requiring ECG gating for full-volume datasets", "Higher frame rates than 2D", "Better lateral resolution", "No need for ECG gating"], correctIndex: 0, rationale: "3D echo has lower temporal resolution (volume rates) compared to 2D frame rates. Full-volume datasets require ECG-gated multi-beat stitching which can introduce stitch artifacts with irregular rhythms (atrial fibrillation).", difficulty: 3, category: "Imaging Techniques", topic: "3D Echo" },
  { id: "cardecho-488", stem: "Speckle tracking echocardiography (STE) measures:", options: ["Myocardial deformation (strain) by tracking acoustic markers frame-to-frame throughout the cardiac cycle", "Blood flow velocity through valves", "Transvalvular pressure gradients", "Valve area directly"], correctIndex: 0, rationale: "STE tracks unique acoustic patterns (speckles) in the myocardium from frame to frame, measuring myocardial deformation (strain). It is angle-independent unlike tissue Doppler-derived strain and provides global and regional strain analysis.", difficulty: 2, category: "Imaging Techniques", topic: "Strain/Speckle Tracking" },
  { id: "cardecho-489", stem: "Normal global longitudinal strain (GLS) of the left ventricle is approximately:", options: ["-18% to -22% (negative value indicating shortening)", "-5% to -10%", "+15% to +20%", "0%"], correctIndex: 0, rationale: "Normal GLS is approximately -18% to -22%. The negative sign indicates shortening. GLS >-16% is generally considered abnormal. GLS is more sensitive than LVEF for detecting subclinical systolic dysfunction (e.g., chemotherapy cardiotoxicity).", difficulty: 2, category: "Imaging Techniques", topic: "Strain/Speckle Tracking" },
  { id: "cardecho-490", stem: "GLS is particularly useful for early detection of cardiotoxicity in patients receiving:", options: ["Anthracycline chemotherapy (doxorubicin) or trastuzumab, detecting subclinical dysfunction before EF drops", "Aspirin therapy", "Statin therapy", "Antihypertensive medications"], correctIndex: 0, rationale: "GLS detects subclinical myocardial dysfunction before LVEF declines. A relative decrease >15% from baseline GLS during chemotherapy suggests cardiotoxicity and may prompt treatment modification. This is recommended in ASE/EACVI guidelines.", difficulty: 3, category: "Imaging Techniques", topic: "Strain/Speckle Tracking" },
  { id: "cardecho-491", stem: "The bull's-eye (polar map) display of GLS shows:", options: ["Regional strain values of all 17 LV segments arranged in a circular map with the apex at the center", "Blood flow direction through the heart", "Valve areas in a schematic diagram", "ECG tracing overlay"], correctIndex: 0, rationale: "The bull's-eye map displays GLS for all 17 LV segments: apical segments in the center, mid-ventricular in the middle ring, and basal segments in the outer ring. Color coding shows normal (red) vs reduced (blue) strain, aiding pattern recognition.", difficulty: 2, category: "Imaging Techniques", topic: "Strain/Speckle Tracking" },
  { id: "cardecho-492", stem: "Right ventricular longitudinal strain is measured from which view?", options: ["Apical four-chamber view focused on the RV free wall", "Parasternal short-axis view", "Suprasternal notch view", "Subcostal IVC view"], correctIndex: 0, rationale: "RV free wall longitudinal strain is measured from the RV-focused apical four-chamber view. Normal RV free wall strain is approximately -25% to -30%. Reduced RV strain is associated with poor outcomes in pulmonary hypertension and heart failure.", difficulty: 3, category: "Imaging Techniques", topic: "Strain/Speckle Tracking" },
  { id: "cardecho-493", stem: "Point-of-care echocardiography (POCUS) differs from a comprehensive echo in that it:", options: ["Is a focused, goal-directed examination answering specific clinical questions at the bedside without a full comprehensive assessment", "Replaces the need for formal echocardiography", "Requires the same equipment as a full echo lab", "Always takes longer than a comprehensive study"], correctIndex: 0, rationale: "POCUS is a targeted bedside exam using portable devices to answer specific questions (e.g., is there a pericardial effusion? Is LV function reduced? Is there RV dilation?). It supplements but does not replace comprehensive echocardiography.", difficulty: 1, category: "Imaging Techniques", topic: "Point-of-Care Echo" },
  { id: "cardecho-494", stem: "In the FAST (Focused Assessment with Sonography for Trauma) exam, which cardiac view is obtained?", options: ["Subxiphoid (subcostal) four-chamber view to evaluate for pericardial effusion and cardiac activity", "Parasternal long-axis view", "Apical five-chamber view", "Suprasternal notch view"], correctIndex: 0, rationale: "The FAST exam includes a subxiphoid cardiac view to rapidly detect pericardial effusion in trauma patients. This view avoids interference from rib shadows and pneumothorax, providing reliable cardiac imaging in emergency settings.", difficulty: 1, category: "Imaging Techniques", topic: "Point-of-Care Echo" },
  { id: "cardecho-495", stem: "POCUS assessment for volume status typically includes evaluation of:", options: ["IVC diameter and respiratory variation to estimate right atrial pressure", "Aortic valve area", "Mitral valve gradient", "LVOT diameter"], correctIndex: 0, rationale: "IVC assessment by POCUS provides rapid bedside estimation of volume status and RAP. A small, collapsible IVC suggests low RAP/hypovolemia. A dilated, non-collapsible IVC suggests elevated RAP/volume overload. This guides fluid management.", difficulty: 2, category: "Imaging Techniques", topic: "Point-of-Care Echo" },
  { id: "cardecho-496", stem: "Reverberation artifact on echocardiography appears as:", options: ["Equally spaced parallel lines at multiples of the distance between the transducer and a strong reflector", "A single bright dot", "Color Doppler signal outside the heart", "Enhancement of structures behind a cyst"], correctIndex: 0, rationale: "Reverberation occurs when ultrasound bounces between two strong reflectors (e.g., transducer face and pericardium). The machine interprets the delayed echoes as deeper structures, creating equally spaced duplicate images.", difficulty: 2, category: "Imaging Techniques", topic: "Echo Artifacts" },
  { id: "cardecho-497", stem: "Side lobe artifact can mimic which pathology on echocardiography?", options: ["Intracardiac mass or thrombus when side lobe echoes from adjacent structures appear within the cardiac chambers", "Pericardial effusion", "Aortic dissection", "Mitral valve prolapse"], correctIndex: 0, rationale: "Side lobes are off-axis ultrasound beams that generate weak echoes from strong reflectors (e.g., calcified structures). These echoes are displayed along the main beam axis, potentially mimicking intracardiac masses or thrombi.", difficulty: 3, category: "Imaging Techniques", topic: "Echo Artifacts" },
  { id: "cardecho-498", stem: "Acoustic shadowing occurs when:", options: ["A highly reflective or attenuating structure (calcification, prosthetic valve) blocks ultrasound transmission, creating an echo-free zone behind it", "Ultrasound penetrates too deeply", "The gain is set too low", "Harmonic imaging is used"], correctIndex: 0, rationale: "Dense structures like calcified valves, prosthetic valves, or sternal wires reflect or absorb most of the ultrasound energy, preventing transmission to deeper structures. The resulting shadow obscures structures behind the reflector.", difficulty: 1, category: "Imaging Techniques", topic: "Echo Artifacts" },
  { id: "cardecho-499", stem: "Mirror artifact on echocardiography can create a false appearance of:", options: ["A duplicate cardiac structure appearing on the opposite side of a strong specular reflector like the pericardium or diaphragm", "An enlarged cardiac chamber", "A thickened valve", "Increased Doppler velocity"], correctIndex: 0, rationale: "Mirror artifact occurs when ultrasound reflects off a strong specular surface (pericardium, pleura, diaphragm), creating a duplicate image on the far side. It can mimic pericardial effusion or a mass behind the heart.", difficulty: 3, category: "Imaging Techniques", topic: "Echo Artifacts" },
  { id: "cardecho-500", stem: "Aliasing in pulsed wave Doppler occurs when:", options: ["The blood flow velocity exceeds the Nyquist limit (half the pulse repetition frequency)", "The gain is too high", "The transducer frequency is too low", "Continuous wave Doppler is used"], correctIndex: 0, rationale: "Aliasing occurs when the Doppler shift exceeds the Nyquist limit (PRF/2). The signal wraps around, displaying high velocities on the opposite side of the baseline. Solutions include increasing PRF, shifting baseline, using CW Doppler, or lowering transducer frequency.", difficulty: 2, category: "Imaging Techniques", topic: "Echo Artifacts" },
  { id: "cardecho-501", stem: "The near field clutter artifact in the apical views can be reduced by:", options: ["Using tissue harmonic imaging which suppresses near-field artifacts and improves endocardial definition", "Increasing overall gain", "Using fundamental frequency imaging", "Decreasing depth"], correctIndex: 0, rationale: "Tissue harmonic imaging receives echoes at the second harmonic frequency (2× transmitted frequency). Harmonics are generated in tissue and are less affected by near-field artifacts, chest wall reverberations, and side lobes, improving image quality.", difficulty: 3, category: "Imaging Techniques", topic: "Echo Artifacts" },
  { id: "cardecho-502", stem: "Dropout artifact in the interatrial septum on apical four-chamber view can falsely suggest:", options: ["An atrial septal defect when the septum is parallel to the ultrasound beam", "A ventricular septal defect", "Mitral valve prolapse", "Pericardial effusion"], correctIndex: 0, rationale: "When the ultrasound beam is parallel to the interatrial septum (as in A4C view), poor specular reflection causes dropout, mimicking an ASD. The subcostal view provides perpendicular interrogation and is the best view to confirm or rule out a true ASD.", difficulty: 2, category: "Imaging Techniques", topic: "Echo Artifacts" },
  { id: "cardecho-503", stem: "Echocardiographic quality assurance programs should include:", options: ["Regular image quality review, measurement variability assessment, correlation with surgical/catheterization data, and continuing education", "Only counting the number of studies performed daily", "Only ensuring the machine is turned on", "Annual equipment replacement"], correctIndex: 0, rationale: "QA programs per IAC/ASE standards include: image quality audits, inter- and intra-reader measurement variability, correlation with other modalities (cath, surgery, CMR), turnaround time monitoring, and ongoing sonographer/physician education.", difficulty: 2, category: "Professional Standards", topic: "Quality Assurance" },
  { id: "cardecho-504", stem: "The Intersocietal Accreditation Commission (IAC) accreditation for echocardiography requires:", options: ["Meeting standards for personnel qualifications, equipment, procedures, quality improvement, and case volume", "Only having a functioning ultrasound machine", "A single credentialed sonographer on staff", "No ongoing quality improvement"], correctIndex: 0, rationale: "IAC accreditation requires: qualified physicians (Level 2/3 training) and sonographers (RDCS/RCS credentials), appropriate equipment, written protocols, QA program, adequate case volumes, continuing education, and submission of case studies for review.", difficulty: 2, category: "Professional Standards", topic: "Accreditation" },
  { id: "cardecho-505", stem: "The RDCS (Registered Diagnostic Cardiac Sonographer) credential is awarded by:", options: ["ARDMS (American Registry for Diagnostic Medical Sonography)", "ARRT (American Registry of Radiologic Technologists)", "ASCP (American Society for Clinical Pathology)", "AMA (American Medical Association)"], correctIndex: 0, rationale: "ARDMS awards the RDCS credential in Adult Echo (AE), Pediatric Echo (PE), and Fetal Echo (FE) specialties. Candidates must meet prerequisite requirements and pass the specialty examination. CCI offers the RCS credential as an alternative.", difficulty: 1, category: "Professional Standards", topic: "Accreditation" },
  { id: "cardecho-506", stem: "To maintain RDCS certification, sonographers must:", options: ["Complete continuing medical education (CME) credits and pay renewal fees within the certification period", "Retake the full exam every year", "Only practice for one year after certification", "No maintenance requirements exist"], correctIndex: 0, rationale: "ARDMS requires 30 CME credits every 3 years in the specific credential area for maintenance. This ensures ongoing competency and up-to-date knowledge of evolving echocardiographic techniques and guidelines.", difficulty: 1, category: "Professional Standards", topic: "Accreditation" },
  { id: "cardecho-507", stem: "The ALARA principle in diagnostic ultrasound refers to:", options: ["As Low As Reasonably Achievable - using the minimum ultrasound output necessary to obtain diagnostic information", "Always Lower All Receiver Amplification", "Anterior Lateral Apical Right Anterior scanning protocol", "Automated Left Atrial Ratio Assessment"], correctIndex: 0, rationale: "ALARA is the guiding safety principle for diagnostic ultrasound. It means using the lowest power output, shortest exposure time, and optimal settings to achieve diagnostic quality, minimizing potential bioeffects (thermal and mechanical).", difficulty: 1, category: "Professional Standards", topic: "Safety" },
  { id: "cardecho-508", stem: "The two primary bioeffects of diagnostic ultrasound are:", options: ["Thermal (tissue heating) and mechanical (cavitation)", "Ionizing radiation and chemical toxicity", "Magnetic effects and electrical stimulation", "Gravitational and electromagnetic effects"], correctIndex: 0, rationale: "Thermal effects result from absorption of ultrasound energy causing tissue heating. Mechanical effects include cavitation (formation and collapse of gas bubbles). The thermal index (TI) and mechanical index (MI) are displayed on-screen to monitor these risks.", difficulty: 2, category: "Professional Standards", topic: "Safety" },
  { id: "cardecho-509", stem: "The thermal index (TI) displayed on the ultrasound machine indicates:", options: ["An estimate of the potential temperature rise in tissue from the ultrasound beam", "The room temperature", "The transducer surface temperature", "The patient's body temperature"], correctIndex: 0, rationale: "TI is the ratio of the acoustic power produced to the power required to raise tissue temperature by 1°C. A TI of 2.0 indicates the potential for a 2°C temperature rise. Operators should keep TI as low as practical.", difficulty: 3, category: "Professional Standards", topic: "Safety" },
  { id: "cardecho-510", stem: "The mechanical index (MI) relates to the risk of:", options: ["Cavitation - the formation and collapse of gas-filled bubbles in tissue due to acoustic pressure", "Tissue heating", "Electromagnetic interference", "X-ray exposure"], correctIndex: 0, rationale: "MI = peak rarefactional pressure / √frequency. Higher MI increases the risk of inertial cavitation, especially relevant when contrast agents (microbubbles) are present. MI should be kept low during contrast studies to avoid bubble destruction.", difficulty: 3, category: "Professional Standards", topic: "Safety" },
  { id: "cardecho-511", stem: "Ergonomic best practices for cardiac sonographers include:", options: ["Maintaining neutral wrist position, adjusting table height, using arm support, and taking regular breaks to prevent repetitive strain injury", "Scanning with maximum pressure at all times", "Using only one hand position throughout the study", "Extending scanning sessions to 2 hours without breaks"], correctIndex: 0, rationale: "Cardiac sonographers have high rates of work-related musculoskeletal disorders (WRMSD). Ergonomic practices include neutral joint positions, adjustable equipment, scanning arm support, microbreaks, and limiting continuous scanning time.", difficulty: 1, category: "Professional Standards", topic: "Safety" },
  { id: "cardecho-512", stem: "Informed consent for TEE should include discussion of:", options: ["Risks of esophageal perforation, bleeding, aspiration, and reaction to sedation", "Only the benefits of the procedure", "No risks since TEE is non-invasive", "Only the cost of the procedure"], correctIndex: 0, rationale: "TEE is semi-invasive and requires informed consent. Risks include esophageal perforation (<0.03%), bleeding (especially with anticoagulation), aspiration, dental injury, laryngospasm, adverse reaction to sedation, and arrhythmias.", difficulty: 2, category: "Professional Standards", topic: "Professional Ethics" },
  { id: "cardecho-513", stem: "Patient confidentiality requirements for echocardiographic images and reports are governed by:", options: ["HIPAA (Health Insurance Portability and Accountability Act) regulations", "Medicare billing codes only", "Hospital marketing guidelines", "Equipment manufacturer recommendations"], correctIndex: 0, rationale: "HIPAA mandates protection of patient health information (PHI) including echocardiographic images, reports, and measurements. This includes secure storage, limited access, proper de-identification for research, and encryption for electronic transmission.", difficulty: 1, category: "Professional Standards", topic: "Professional Ethics" },
  { id: "cardecho-514", stem: "When a sonographer discovers an unexpected critical finding during scanning, the appropriate action is to:", options: ["Immediately notify the supervising physician so that urgent clinical decisions can be made", "Complete the entire study before reporting any findings", "Document the finding and report it at the end of the day", "Only include it in the written report"], correctIndex: 0, rationale: "Critical findings (cardiac tamponade, aortic dissection, severe acute valve dysfunction, large mobile thrombus) require immediate communication to the supervising/attending physician. Delays in reporting critical findings can compromise patient safety.", difficulty: 1, category: "Professional Standards", topic: "Professional Ethics" },
  { id: "cardecho-515", stem: "Scope of practice for a cardiac sonographer includes:", options: ["Acquiring and optimizing echocardiographic images, performing measurements, and providing preliminary findings to the interpreting physician", "Independently interpreting and finalizing echo reports", "Prescribing medications based on findings", "Ordering additional diagnostic tests independently"], correctIndex: 0, rationale: "Sonographers acquire images, perform measurements, and provide preliminary observations. Final interpretation and clinical correlation are the responsibility of the physician. Sonographers do not independently diagnose, prescribe, or make treatment decisions.", difficulty: 1, category: "Professional Standards", topic: "Professional Ethics" },
  { id: "cardecho-516", stem: "To optimize 2D image quality, the sonographer should first:", options: ["Select the appropriate transducer frequency, adjust depth, and optimize gain settings before beginning measurements", "Start with maximum depth and highest frequency", "Begin measurements immediately without adjustments", "Use the same settings for every patient"], correctIndex: 0, rationale: "Image optimization begins with transducer selection (lower frequency for depth penetration, higher for resolution), adjusting depth to frame the region of interest, optimizing overall and time-gain compensation (TGC), and selecting appropriate focus position.", difficulty: 1, category: "Imaging Techniques", topic: "Image Optimization" },
  { id: "cardecho-517", stem: "Tissue harmonic imaging improves echocardiographic quality by:", options: ["Receiving the second harmonic frequency generated in tissue which has better signal-to-noise ratio and reduced artifacts", "Transmitting at a higher frequency", "Increasing penetration depth", "Using continuous wave Doppler"], correctIndex: 0, rationale: "Harmonics are generated as ultrasound propagates through tissue (nonlinear propagation). The second harmonic has better spatial resolution, reduced near-field artifact, reduced side lobes, and improved endocardial definition compared to fundamental imaging.", difficulty: 3, category: "Imaging Techniques", topic: "Image Optimization" },
  { id: "cardecho-518", stem: "Increasing the ultrasound transducer frequency will:", options: ["Improve axial resolution but decrease penetration depth", "Decrease resolution and increase penetration", "Have no effect on image quality", "Only affect color Doppler"], correctIndex: 0, rationale: "Higher frequency = shorter wavelength = better axial resolution but greater attenuation (less penetration). Lower frequency = longer wavelength = better penetration but reduced resolution. This is the fundamental frequency-resolution trade-off.", difficulty: 2, category: "Imaging Techniques", topic: "Image Optimization" },
  { id: "cardecho-519", stem: "The time-gain compensation (TGC) controls are adjusted to:", options: ["Compensate for attenuation by increasing gain for deeper structures to achieve uniform brightness throughout the image", "Change the transducer frequency", "Alter the frame rate", "Modify the Doppler baseline"], correctIndex: 0, rationale: "TGC (also called depth-gain compensation) uses multiple slider controls to independently adjust gain at different depths. This compensates for natural attenuation of ultrasound as it travels deeper, creating uniform image brightness.", difficulty: 2, category: "Imaging Techniques", topic: "Image Optimization" },
  { id: "cardecho-520", stem: "The Nyquist limit in pulsed wave Doppler is equal to:", options: ["Half the pulse repetition frequency (PRF/2)", "Twice the PRF", "The transducer frequency", "The Doppler angle"], correctIndex: 0, rationale: "The Nyquist limit (maximum detectable velocity without aliasing) equals PRF/2. To measure higher velocities, the sonographer can increase the PRF, shift the baseline, use a lower frequency transducer, or switch to CW Doppler.", difficulty: 2, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-521", stem: "Color flow Doppler mapping displays:", options: ["Mean blood flow velocity and direction encoded as red (toward) and blue (away from) the transducer", "Peak instantaneous velocity", "Only turbulent flow", "Tissue velocity exclusively"], correctIndex: 0, rationale: "Color Doppler uses autocorrelation to display mean velocity and direction: red = toward transducer, blue = away (BART mnemonic). Variance/turbulence may be shown as mosaic or green overlay. It provides spatial orientation of blood flow patterns.", difficulty: 1, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-522", stem: "The Doppler equation relates the Doppler shift to velocity by:", options: ["Δf = (2 × f₀ × v × cos θ) / c, where θ is the angle between the beam and flow direction", "Δf = f₀ × v", "Δf = v / c", "Δf = f₀ / cos θ"], correctIndex: 0, rationale: "The Doppler equation: Δf = (2f₀v cosθ)/c. Velocity accuracy depends on the cosine of the angle between the ultrasound beam and flow direction. At 0° (parallel), cosine = 1 (accurate). At angles >20°, velocity is increasingly underestimated.", difficulty: 3, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-523", stem: "For accurate Doppler velocity measurements, the angle between the ultrasound beam and blood flow should be:", options: ["<20 degrees (ideally parallel/0 degrees) to minimize velocity underestimation", ">60 degrees", "Exactly 90 degrees (perpendicular)", "Angle does not matter"], correctIndex: 0, rationale: "At 0°, cos(0) = 1 and measured velocity equals true velocity. At 20°, cos(20°) = 0.94 (6% error, acceptable). At 60°, cos(60°) = 0.5 (50% underestimation). Perpendicular alignment (90°) yields no Doppler signal.", difficulty: 2, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-524", stem: "Continuous wave (CW) Doppler differs from pulsed wave (PW) Doppler in that CW:", options: ["Can measure very high velocities without aliasing but cannot determine the exact depth/location of the signal", "Can localize the exact depth of flow", "Has a limited velocity range", "Uses a single piezoelectric element for both transmitting and receiving"], correctIndex: 0, rationale: "CW Doppler uses separate transmit and receive crystals operating continuously, sampling all velocities along the beam. It has no Nyquist limit but lacks range resolution. PW provides range resolution but is limited by the Nyquist limit.", difficulty: 2, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-525", stem: "High pulse repetition frequency (HPRF) Doppler is used to:", options: ["Extend the measurable velocity range of PW Doppler by placing multiple sample volumes along the beam", "Decrease the maximum measurable velocity", "Replace continuous wave Doppler entirely", "Improve 2D image resolution"], correctIndex: 0, rationale: "HPRF increases the PRF beyond that needed for a single sample volume, creating multiple sample gates along the beam. This raises the Nyquist limit while maintaining some range resolution, bridging the gap between PW and CW Doppler.", difficulty: 4, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-526", stem: "A large pericardial effusion on echocardiography is defined as an echo-free space of:", options: [">20 mm measured in diastole", ">5 mm in systole", ">10 mm in systole only", ">50 mm circumferentially"], correctIndex: 0, rationale: "Pericardial effusion grading: trivial/trace (seen only in systole), small (<10 mm), moderate (10-20 mm), large (>20 mm). Measurements are taken in diastole. Large effusions correspond to approximately >500 mL of fluid.", difficulty: 1, category: "Pericardial Disease", topic: "Pericardial Disease" },
  { id: "cardecho-527", stem: "Echocardiographic signs of cardiac tamponade include:", options: ["RA systolic collapse, RV diastolic collapse, exaggerated respiratory variation of mitral/tricuspid inflow, and dilated non-collapsing IVC", "Only the presence of pericardial effusion", "LV hypertrophy", "Aortic valve calcification"], correctIndex: 0, rationale: "Tamponade is a clinical-hemodynamic diagnosis. Echo signs include: RA collapse (most sensitive), RV diastolic collapse (more specific), swinging heart, >25% respiratory variation in mitral inflow, >40% in tricuspid inflow, and plethoric IVC.", difficulty: 2, category: "Pericardial Disease", topic: "Pericardial Disease" },
  { id: "cardecho-528", stem: "Pericardial effusion can be distinguished from pleural effusion by:", options: ["Pericardial effusion tracks anterior to the descending aorta while pleural effusion tracks posterior to it in the PLAX view", "Pericardial effusion is always larger", "Pleural effusion is always echo-free", "They cannot be distinguished by echocardiography"], correctIndex: 0, rationale: "In the PLAX view, the descending aorta is a key landmark. Pericardial effusion is anterior to the descending aorta (between the heart and aorta), while pleural effusion extends posterior to the aorta.", difficulty: 2, category: "Pericardial Disease", topic: "Pericardial Disease" },
  { id: "cardecho-529", stem: "Constrictive pericarditis on echocardiography shows:", options: ["Septal bounce (ventricular interdependence), respiratory variation in mitral inflow >25%, and pericardial thickening/calcification", "Pericardial effusion with tamponade", "LV dilation with reduced EF", "Aortic root dilation"], correctIndex: 0, rationale: "Constriction is caused by a stiff, non-compliant pericardium that limits ventricular filling. Key echo features: septal bounce/shift with respiration, enhanced ventricular interdependence, annulus reversus (medial e' > lateral e'), and restrictive filling pattern.", difficulty: 3, category: "Pericardial Disease", topic: "Pericardial Disease" },
  { id: "cardecho-530", stem: "Aortic dissection on echocardiography is identified by:", options: ["An intimal flap separating the true and false lumens within the aortic wall", "Aortic valve thickening without flap", "Uniform aortic wall thickening", "Pericardial calcification"], correctIndex: 0, rationale: "Aortic dissection shows a linear echogenic intimal flap within the aortic lumen, creating true and false lumens. Color Doppler shows differential flow in each lumen. TEE has >95% sensitivity for thoracic dissection; TTE has limited sensitivity (~60-80%).", difficulty: 2, category: "Aortic Pathology", topic: "Aortic Pathology" },
  { id: "cardecho-531", stem: "Stanford Type A aortic dissection involves:", options: ["The ascending aorta regardless of the site of the intimal tear or distal extension", "Only the descending aorta distal to the left subclavian artery", "Only the aortic arch", "Only the abdominal aorta"], correctIndex: 0, rationale: "Stanford Type A: any dissection involving the ascending aorta (requires emergent surgery). Stanford Type B: dissection limited to the descending aorta distal to the left subclavian artery (usually managed medically unless complicated).", difficulty: 2, category: "Aortic Pathology", topic: "Aortic Pathology" },
  { id: "cardecho-532", stem: "Complications of Type A aortic dissection detectable by echocardiography include:", options: ["Aortic regurgitation, pericardial effusion/tamponade, coronary ostial involvement, and wall motion abnormalities", "Mitral stenosis", "Pulmonary valve stenosis", "Tricuspid atresia"], correctIndex: 0, rationale: "Type A dissection can cause acute AR (dissection disrupts aortic valve support), pericardial effusion/tamponade (rupture into pericardium), coronary malperfusion (dissection flap covers ostia causing MI), and proximal extension affecting the arch vessels.", difficulty: 3, category: "Aortic Pathology", topic: "Aortic Pathology" },
  { id: "cardecho-533", stem: "Aortic root dilation should be monitored echocardiographically in patients with:", options: ["Marfan syndrome, bicuspid aortic valve, Loeys-Dietz syndrome, and familial thoracic aortic aneurysm", "Isolated mitral valve prolapse without connective tissue disease", "Normal tricuspid aortic valve with no risk factors", "Uncomplicated atrial fibrillation"], correctIndex: 0, rationale: "Conditions predisposing to aortic root dilation and potential dissection include Marfan syndrome (fibrillin-1 mutation), bicuspid aortic valve, Loeys-Dietz (TGFBR mutations), Ehlers-Danlos type IV, Turner syndrome, and familial thoracic aortic aneurysm.", difficulty: 2, category: "Aortic Pathology", topic: "Aortic Pathology" },
  { id: "cardecho-534", stem: "The normal aortic root diameter at the sinuses of Valsalva in adults is approximately:", options: ["<40 mm (or <21 mm/m² indexed to BSA)", ">50 mm", "<20 mm", ">60 mm"], correctIndex: 0, rationale: "Normal aortic root diameter at sinuses of Valsalva is approximately 31-37 mm (varies with age, sex, BSA). Values >40 mm or indexed >21 mm/m² are considered dilated. Surgical thresholds depend on underlying condition (45 mm for Marfan, 55 mm for bicuspid AV).", difficulty: 2, category: "Aortic Pathology", topic: "Aortic Pathology" },
  { id: "cardecho-535", stem: "Atheroma of the aortic arch detected on TEE is graded as complex when:", options: ["It is ≥4 mm thick, has mobile components, or contains ulceration", "It is <2 mm thick and smooth", "It is only seen on TTE", "It has no clinical significance"], correctIndex: 0, rationale: "Complex aortic atheroma (≥4 mm thick, mobile, ulcerated) is associated with increased risk of embolic stroke and systemic embolism. TEE is the best imaging modality for arch atheroma assessment, particularly in patients with cryptogenic stroke.", difficulty: 3, category: "Aortic Pathology", topic: "Aortic Pathology" },
  { id: "cardecho-536", stem: "The most common primary benign cardiac tumor is:", options: ["Myxoma", "Rhabdomyoma", "Fibroma", "Lipoma"], correctIndex: 0, rationale: "Myxoma accounts for approximately 50% of primary cardiac tumors. About 75% occur in the left atrium, typically attached to the interatrial septum near the fossa ovalis by a stalk. They can cause obstruction, embolization, and constitutional symptoms.", difficulty: 1, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-537", stem: "Left atrial myxoma typically appears on echocardiography as:", options: ["A mobile, pedunculated mass attached to the interatrial septum near the fossa ovalis that may prolapse through the mitral valve", "A fixed, calcified mass in the LA appendage", "A sessile mass on the posterior LA wall", "Multiple small masses throughout all chambers"], correctIndex: 0, rationale: "LA myxomas are typically solitary, pedunculated (stalked), heterogeneous masses attached to the IAS. They may prolapse through the mitral valve during diastole causing obstruction (plop sound) and positional symptoms.", difficulty: 2, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-538", stem: "The most common primary malignant cardiac tumor is:", options: ["Angiosarcoma", "Myxoma", "Rhabdomyoma", "Lipoma"], correctIndex: 0, rationale: "Angiosarcoma is the most common primary malignant cardiac tumor (approximately 30% of malignant cardiac tumors). It typically involves the right atrium and pericardium, often presenting with hemorrhagic pericardial effusion and rapid growth.", difficulty: 3, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-539", stem: "Papillary fibroelastoma is a benign tumor that:", options: ["Typically attaches to valve surfaces and can cause embolic events due to its frond-like surface", "Fills the entire ventricular cavity", "Only occurs in the pericardium", "Is always asymptomatic and requires no follow-up"], correctIndex: 0, rationale: "Papillary fibroelastomas are small (usually <1.5 cm), pedunculated tumors with a characteristic sea-anemone appearance. They most commonly attach to the aortic or mitral valve and can cause stroke or coronary embolization from surface thrombi.", difficulty: 3, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-540", stem: "Rhabdomyoma is the most common cardiac tumor in:", options: ["Children, often associated with tuberous sclerosis and frequently regressing spontaneously", "Elderly adults", "Immunocompromised patients", "Patients with Marfan syndrome"], correctIndex: 0, rationale: "Rhabdomyomas are the most common pediatric cardiac tumor (60%). They are strongly associated with tuberous sclerosis (50-80%). Most are multiple, intramural, and involve the ventricles. The majority spontaneously regress in the first few years of life.", difficulty: 2, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-541", stem: "Metastatic cardiac tumors are approximately how many times more common than primary cardiac tumors?", options: ["20-40 times more common", "Equal in frequency", "Half as common", "2-3 times more common"], correctIndex: 0, rationale: "Metastatic cardiac tumors are 20-40 times more common than primary tumors. Common primary sites metastasizing to the heart include lung, breast, melanoma, lymphoma, and renal cell carcinoma. Pericardial involvement is most common.", difficulty: 3, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-542", stem: "A vegetation on echocardiography in infective endocarditis appears as:", options: ["An irregularly shaped, echogenic, oscillating mass attached to the upstream side of a valve leaflet", "A smooth, round, non-mobile calcification", "A cystic structure within the myocardium", "An echo-free space behind the valve"], correctIndex: 0, rationale: "Vegetations are typically attached to the low-pressure side of the valve (atrial side of AV valves, ventricular side of semilunar valves), are oscillating/mobile, and have irregular borders. Size >10 mm is associated with higher embolic risk.", difficulty: 2, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-543", stem: "Lambl excrescences on cardiac valves are:", options: ["Small, filamentous strands on valve closure lines that are degenerative and typically benign", "Large vegetations from endocarditis", "Malignant tumors", "Thrombi requiring anticoagulation"], correctIndex: 0, rationale: "Lambl excrescences are thin (<1 mm), filamentous strands at valve closure sites resulting from wear and tear. They are common incidental findings on TEE, especially in elderly patients, and are usually considered benign, though large strands may rarely cause embolism.", difficulty: 3, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-544", stem: "LV apical thrombus is best detected using which technique?", options: ["Contrast echocardiography, which has significantly higher sensitivity than non-contrast imaging", "M-mode echocardiography alone", "Continuous wave Doppler", "Color Doppler of the mitral inflow"], correctIndex: 0, rationale: "Contrast echo has >90% sensitivity for LV thrombus detection compared to ~30-60% for non-contrast echo. Near-field artifacts and poor apical windows often obscure thrombi on standard imaging. CMR is the gold standard.", difficulty: 3, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-545", stem: "The moderator band in the right ventricle can be mistaken for:", options: ["An intracardiac mass or thrombus if the sonographer is unfamiliar with normal RV anatomy", "A pericardial effusion", "An aortic dissection flap", "A mitral valve vegetation"], correctIndex: 0, rationale: "The moderator band is a normal muscular structure in the RV connecting the interventricular septum to the anterior papillary muscle. It is often prominent and can be misidentified as a mass, thrombus, or vegetation on echocardiography.", difficulty: 2, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-546", stem: "The Chiari network is a normal variant that appears as:", options: ["A filamentous, mobile structure in the right atrium representing a remnant of the right valve of the sinus venosus", "A mass in the left atrium", "A vegetation on the tricuspid valve", "A thrombus in the IVC"], correctIndex: 0, rationale: "The Chiari network is a fenestrated, mobile, web-like structure in the RA, representing an embryological remnant of the right valve of the sinus venosus. It is present in 2-3% of people and can be mistaken for a mass, thrombus, or vegetation.", difficulty: 3, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-547", stem: "The eustachian valve is a normal structure located at:", options: ["The junction of the IVC and right atrium, directing fetal blood toward the foramen ovale", "The junction of the SVC and right atrium", "The coronary sinus ostium", "The left atrial appendage"], correctIndex: 0, rationale: "The eustachian valve is a remnant of the embryonic right sinus venosus valve at the IVC-RA junction. In fetal life, it directed oxygenated blood from the IVC through the foramen ovale to the LA. It can be prominent and mimic a mass on echo.", difficulty: 2, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-548", stem: "Crista terminalis is a normal RA structure that can be misidentified as:", options: ["A right atrial mass or thrombus, particularly on TEE", "A left atrial mass", "An aortic dissection flap", "A ventricular septal defect"], correctIndex: 0, rationale: "The crista terminalis is a muscular ridge on the posterolateral RA wall separating the smooth posterior RA from the trabeculated anterior RA (pectinate muscles). It appears as a thick ridge that can be mistaken for a mass, especially on TEE.", difficulty: 2, category: "Cardiac Masses", topic: "Cardiac Masses" },
  { id: "cardecho-549", stem: "When evaluating prosthetic valve function, the expected normal gradient depends on:", options: ["Valve type (mechanical vs bioprosthetic), size, position, and manufacturer specifications", "Only the patient's blood pressure", "Only the heart rate", "The age of the patient alone"], correctIndex: 0, rationale: "Normal gradients vary by valve type and size. Mechanical valves generally have lower gradients than bioprosthetic valves of the same size. Smaller valves have higher expected gradients. Reference values from the manufacturer must be consulted.", difficulty: 3, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-550", stem: "Prosthetic valve obstruction is suggested by:", options: ["Increased gradients above expected reference values, decreased effective orifice area, and abnormal disc/leaflet motion", "Normal expected gradients", "Trivial physiologic regurgitation", "Normal disc motion"], correctIndex: 0, rationale: "Prosthetic valve obstruction can result from pannus, thrombus, or tissue ingrowth. Echo findings include elevated gradients above expected values, prolonged PHT (mitral), reduced EOA, abnormal disc motion (fluoroscopy confirms), and increased DVI.", difficulty: 3, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-551", stem: "The dimensionless velocity index (DVI) for assessing aortic prosthetic valves is:", options: ["LVOT VTI / prosthetic AV VTI, with values <0.25 suggesting significant obstruction", "AV VTI / LVOT VTI", "Peak velocity × heart rate", "Mean gradient / peak velocity"], correctIndex: 0, rationale: "DVI = LVOT VTI / AV VTI (or LVOT peak velocity / AV peak velocity). Normal DVI for prosthetic aortic valves varies by type but <0.25 is generally concerning for significant obstruction. DVI is independent of flow conditions.", difficulty: 4, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-552", stem: "Paravalvular leak of a prosthetic valve is characterized by:", options: ["A regurgitant jet originating outside the sewing ring between the prosthesis and native annular tissue", "Regurgitation through the center of the valve", "Normal physiologic washing jets", "A stenotic jet through the valve"], correctIndex: 0, rationale: "Paravalvular leaks occur at the interface between the prosthetic sewing ring and native tissue. They originate outside the valve ring, unlike central regurgitation. TEE is superior to TTE for detecting and quantifying paravalvular leaks.", difficulty: 3, category: "Imaging Techniques", topic: "Doppler Techniques" },
  { id: "cardecho-553", stem: "During TEE probe insertion, the sonographer should ensure the patient is:", options: ["In the left lateral decubitus position with the neck flexed, after appropriate sedation and topical pharyngeal anesthesia", "Supine with neck extended", "In the right lateral position without sedation", "Standing upright"], correctIndex: 0, rationale: "Left lateral decubitus position prevents aspiration, neck flexion facilitates probe passage, and topical anesthesia (lidocaine spray) reduces gag reflex. Moderate sedation (midazolam, fentanyl) is typically administered. Continuous monitoring of vitals and O2 saturation is required.", difficulty: 2, category: "Imaging Techniques", topic: "TEE Indications" },
  { id: "cardecho-554", stem: "The standard TEE examination includes views obtained at which esophageal levels?", options: ["Upper esophageal (aortic arch), mid-esophageal (four-chamber, two-chamber, LAX views), and transgastric (short-axis, deep views)", "Only mid-esophageal views", "Only transgastric views", "Only upper esophageal views"], correctIndex: 0, rationale: "A comprehensive TEE exam includes 28 standard views at three levels: upper esophageal (aortic arch, SVC), mid-esophageal (four-chamber, commissural, two-chamber, LAX, bicaval, AV SAX/LAX), and transgastric (SAX, two-chamber, LAX, deep five-chamber, RV inflow).", difficulty: 3, category: "Imaging Techniques", topic: "TEE Indications" },
  { id: "cardecho-555", stem: "Strain rate imaging measures:", options: ["The rate of myocardial deformation (how quickly the myocardium shortens or lengthens per unit time)", "Absolute displacement of the myocardium", "Blood flow velocity", "Valve area"], correctIndex: 0, rationale: "Strain rate is the temporal derivative of strain (strain/time, units: 1/s or s⁻¹). It reflects the velocity of deformation and is less load-dependent than strain. Peak systolic strain rate is typically -1.0 to -1.5 s⁻¹ for the LV.", difficulty: 4, category: "Imaging Techniques", topic: "Strain/Speckle Tracking" },
  { id: "cardecho-556", stem: "Circumferential strain is measured from which echocardiographic view?", options: ["Parasternal short-axis view, measuring shortening in the circumferential direction", "Apical four-chamber view", "Apical two-chamber view", "Suprasternal notch view"], correctIndex: 0, rationale: "Circumferential strain measures myocardial shortening along the circumference of the LV in the short-axis plane. Normal circumferential strain is approximately -20% to -25%. It is complementary to longitudinal strain from apical views.", difficulty: 3, category: "Imaging Techniques", topic: "Strain/Speckle Tracking" },
  { id: "cardecho-557", stem: "Mechanical dyssynchrony of the left ventricle can be assessed by:", options: ["Speckle tracking to evaluate time-to-peak strain differences between LV segments", "Aortic valve area calculation", "Mitral inflow E/A ratio", "IVC diameter measurement"], correctIndex: 0, rationale: "Speckle tracking can identify mechanical dyssynchrony by measuring the time from QRS onset to peak systolic strain for each LV segment. A large spread in time-to-peak strain (>130 ms between earliest and latest segments) suggests dyssynchrony.", difficulty: 4, category: "Imaging Techniques", topic: "Strain/Speckle Tracking" },
  { id: "cardecho-558", stem: "In stress echocardiography, a wall motion score index (WMSI) is calculated by:", options: ["Summing individual segment scores (1=normal, 2=hypokinetic, 3=akinetic, 4=dyskinetic, 5=aneurysmal) and dividing by the number of segments assessed", "Measuring peak velocity across the aortic valve", "Calculating the E/A ratio", "Measuring IVC diameter"], correctIndex: 0, rationale: "WMSI = sum of segment scores / number of segments scored. A normal WMSI = 1.0 (all segments normal). Higher values indicate worse wall motion. An increase in WMSI from rest to stress suggests inducible ischemia.", difficulty: 2, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-559", stem: "Vasodilator stress agents (dipyridamole, regadenoson) used in stress echo work by:", options: ["Causing coronary vasodilation that induces flow heterogeneity between normal and stenotic coronary territories", "Directly increasing heart rate like dobutamine", "Causing coronary vasoconstriction", "Having no effect on coronary blood flow"], correctIndex: 0, rationale: "Vasodilator agents cause maximal coronary dilation in normal arteries but cannot dilate already maximally dilated vessels distal to stenoses, creating flow heterogeneity (coronary steal). They are primarily used with perfusion imaging but can also induce wall motion abnormalities.", difficulty: 3, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-560", stem: "A negative stress echocardiogram (normal response) shows:", options: ["Augmentation of wall motion in all segments with no new wall motion abnormalities at peak stress", "New akinesis in the anterior wall", "Decrease in ejection fraction", "Dilation of the LV cavity at peak stress"], correctIndex: 0, rationale: "Normal stress response: all segments become hyperkinetic at peak stress, EF increases, LV cavity decreases in size. An abnormal response includes new/worsening WMA, failure to augment, LV cavity dilation, or decrease in EF.", difficulty: 1, category: "Imaging Techniques", topic: "Stress Echo Protocols" },
  { id: "cardecho-561", stem: "The role of 3D echocardiography in mitral valve assessment includes:", options: ["En-face visualization of the mitral valve showing exact location of prolapse or flail segments for surgical planning", "Only measuring mitral valve gradient", "Replacing all 2D measurements", "Assessing only mitral stenosis severity"], correctIndex: 0, rationale: "3D echo provides a unique en-face (surgeon's) view of the mitral valve, identifying specific scallop involvement (A1-A3, P1-P3), commissural pathology, cleft, and annular geometry. This information is critical for determining repairability.", difficulty: 3, category: "Imaging Techniques", topic: "3D Echo" },
  { id: "cardecho-562", stem: "3D echo measurement of the mitral valve annulus is important for:", options: ["Transcatheter mitral valve repair/replacement planning (e.g., MitraClip or TMVR sizing)", "Routine blood pressure measurement", "Chest X-ray interpretation", "ECG analysis"], correctIndex: 0, rationale: "3D echo provides accurate mitral annular dimensions (anteroposterior diameter, commissural width, area, circumference) essential for sizing transcatheter devices. The saddle-shaped mitral annulus is better characterized by 3D than 2D measurements.", difficulty: 3, category: "Imaging Techniques", topic: "3D Echo" },
  { id: "cardecho-563", stem: "When performing a POCUS exam for acute dyspnea, the sonographer should assess:", options: ["LV function, RV size and function, pericardial effusion, IVC for volume status, and lung B-lines for pulmonary edema", "Only the aortic valve gradient", "Only the liver size", "Only the thyroid gland"], correctIndex: 0, rationale: "POCUS for acute dyspnea uses a systematic approach: cardiac views (LV/RV function, effusion, valves), IVC (volume status), and lung ultrasound (B-lines for pulmonary edema, pleural effusion, consolidation). This rapid assessment guides emergency management.", difficulty: 2, category: "Imaging Techniques", topic: "Point-of-Care Echo" },
  { id: "cardecho-564", stem: "B-lines on lung ultrasound in the setting of heart failure represent:", options: ["Interstitial pulmonary edema, appearing as vertical hyperechoic artifacts extending from the pleural line to the bottom of the screen", "Normal lung aeration", "Pneumothorax", "Pleural thickening only"], correctIndex: 0, rationale: "B-lines are vertical, laser-like artifacts arising from the pleural line that move with respiration and extend to the screen bottom. ≥3 B-lines per intercostal space in ≥2 zones bilaterally indicates interstitial edema. They correlate with PCWP.", difficulty: 2, category: "Imaging Techniques", topic: "Point-of-Care Echo" },
  { id: "cardecho-565", stem: "The focused cardiac ultrasound (FoCUS) protocol is different from a comprehensive echo in that it:", options: ["Uses limited views to answer binary clinical questions (yes/no) rather than providing quantitative measurements", "Includes all standard measurements and Doppler assessments", "Takes longer than a comprehensive study", "Requires RDCS certification to perform"], correctIndex: 0, rationale: "FoCUS uses limited views (parasternal, apical, subcostal) to answer specific questions: Is there a pericardial effusion? Is LV function severely reduced? Is the RV dilated? It does not replace a comprehensive echo but guides acute management.", difficulty: 2, category: "Imaging Techniques", topic: "Point-of-Care Echo" },
  { id: "cardecho-566", stem: "Axial resolution in ultrasound imaging is determined by:", options: ["The spatial pulse length (shorter pulse length = better axial resolution), which depends on frequency and number of cycles per pulse", "The beam width", "The frame rate", "The transducer aperture"], correctIndex: 0, rationale: "Axial resolution = spatial pulse length / 2. Shorter pulses (higher frequency, fewer cycles per pulse) improve axial resolution. Axial resolution is typically the best resolution dimension in ultrasound (0.5-1 mm for cardiac frequencies).", difficulty: 3, category: "Imaging Techniques", topic: "Image Optimization" },
  { id: "cardecho-567", stem: "Lateral resolution in ultrasound is determined by:", options: ["The beam width at the point of interest, which is narrowest at the focal zone", "The transducer frequency only", "The pulse repetition frequency", "The gain setting"], correctIndex: 0, rationale: "Lateral resolution equals the beam width and is best at the focal zone where the beam is narrowest. It degrades in the near and far fields. Adjusting focus to the region of interest optimizes lateral resolution.", difficulty: 3, category: "Imaging Techniques", topic: "Image Optimization" },
  { id: "cardecho-568", stem: "Frame rate in 2D echocardiography is affected by:", options: ["Depth, sector width, line density, and number of focal zones - reducing any of these increases frame rate", "Only the transducer frequency", "Only the gain setting", "Only the patient's heart rate"], correctIndex: 0, rationale: "Frame rate = PRF / (lines per frame). Reducing depth, narrowing sector width, decreasing line density, or reducing focal zones decreases the time per frame, increasing frame rate. Higher frame rates improve temporal resolution for rapid cardiac motion.", difficulty: 3, category: "Imaging Techniques", topic: "Image Optimization" },
  { id: "cardecho-569", stem: "The sonographer notices color Doppler bleeding outside the cardiac chambers into surrounding tissue. This artifact is caused by:", options: ["Excessive color gain setting or wall filter set too low, causing color signals to appear in non-flowing tissue", "Correct gain and filter settings", "A true finding of extracardiac blood flow", "Equipment malfunction requiring immediate repair"], correctIndex: 0, rationale: "Color Doppler bleeding (color flash) occurs when color gain is too high or wall filters are too low, causing tissue motion or noise to be interpreted as blood flow. Reducing color gain, increasing wall filter, or adjusting PRF eliminates this artifact.", difficulty: 2, category: "Imaging Techniques", topic: "Echo Artifacts" },
];
